                        // Check parity: P(nums1[i] - nums1[j]) = P(nums1[i]) XOR P(nums1[j])
                        boolean isOdd_diff = isOdd1[i] ^ isOdd1[j];

                        if (isOdd_diff == (targetParity == 1)) {
                            canAchieveTarget = true;
                            break;
                        }
                    }
                }
            }

            if (!canAchieveTarget) {
                return false;
            }
