        // 1. Parity(nums1[i])
        // 2. Parity(nums1[i] - nums1[j]) = Parity(nums1[i]) - Parity(nums1[j]) (modulo 2)
        //    Parity(nums1[i] - nums1[j]) is 0 (even) if Parity(nums1[i]) == Parity(nums1[j])
        //    Parity(nums1[i] - nums1[j]) is 1 (odd) if Parity(nums1[i]) != Parity(nums1[j])

        // Let p_i = nums1[i] % 2.
        // Choice 1 parity: p_i
        // Choice 2 parity: p_i XOR p_j (since x - y has the same parity as x + y)

